-- [[ 1. BAGIAN BYPASS & GANTI NAMA ]] --
local old_http; old_http = hookfunction(game.HttpGet, function(self, url)
    local res = old_http(self, url)
    if url:find("ringta") or url:find("deadrails") then
        res = res:gsub("ringta", "Error##!"):gsub("Ringta", "Error##!")
        res = res:gsub("is_creator%s*=%s*false", "is_creator = true")
        res = res:gsub("early_access%s*=%s*false", "early_access = true")
        res = res:gsub("content_creator%s*=%s*false", "content_creator = true")
        print("Bypass Success: Error##!")
    end
    return res
end)

local old_load; old_load = hookfunction(loadstring, function(c)
    return old_load(c:gsub("ringta", "Error##!"))
end)

